            conditions = filter_conditions_str.split(',')
            for condition in conditions:
                if '=' in condition:
                    col, val = condition.split('=', 1)
                    col = col.strip()
                    val = val.strip()

                    if col not in ALLOWED_COLUMNS.get(table_name, set()):
                        return jsonify({"error": f"Invalid filter column '{col}' for table '{table_name}'."}), 403

                    where_clauses.append(sql.SQL("{} = %s").format(sql.Identifier(col)))
                    where_params.append(val)
